hooks.command:
python3 -c "
import sys, json
data = json.load(sys.stdin)
cmd = data.get('tool_input', {}).get('command', '')
protected = ['expense_tracker.db', '.env', 'migrations/']
dangerous = ['rm ', 'rm -', 'unlink ', 'truncate ', 'Remove-Item', 'del ', 'del /']
for d in dangerous:
    if d in cmd:
        for p in protected:
            if p in cmd:
                print(json.dumps({"decision": "block", "reason": f"Cannot run destructive command on protected file: {p}"}))
                sys.exit(0)
"
